module reg_32bit(reset_clk, rst, en, D, Q);
    input reset_clk;
    input rst;
    input en;
    input [31:0] D;
    output reg [31:0] Q;

    always @(posedge reset_clk or posedge rst) begin
        if (rst)
            Q <= 32'b0;
        else if (en)
            Q <= D;
    end
endmodule
